10: 	"github.com/grafana/grafana/pkg/services/quota"
11: 	"github.com/grafana/grafana/pkg/services/sqlstore"
12: )
13: 
14: type sqlStore struct {
15: 	db db.DB
16: }
17: 
18: // timeNow makes it possible to test usage of time
19: var timeNow = time.Now
20: 
21: func (ss *sqlStore) GetAllAPIKeys(ctx context.Context, orgID int64) ([]*apikey.APIKey, error) {
22: 	result := make([]*apikey.APIKey, 0)
23: 	err := ss.db.WithDbSession(ctx, func(dbSession *db.Session) error {
24: 		sess := dbSession.Where("service_account_id IS NULL").Asc("name")
25: 		if orgID != -1 {
26: 			sess = sess.Where("org_id=?", orgID)
27: 		}
28: 		return sess.Find(&result)
29: 	})
30: 	return result, err
31: }
32: 
33: func (ss *sqlStore) AddAPIKey(ctx context.Context, cmd *apikey.AddCommand) (res *apikey.APIKey, err error) {
34: 	err = ss.db.WithTransactionalDbSession(ctx, func(sess *db.Session) error {
35: 		key := apikey.APIKey{OrgID: cmd.OrgID, Name: cmd.Name}
36: 		exists, _ := sess.Get(&key)
37: 		if exists {
38: 			return apikey.ErrDuplicate
39: 		}
40: 
41: 		updated := timeNow()
42: 		var expires *int64 = nil
43: 		if cmd.SecondsToLive > 0 {
44: 			v := updated.Add(time.Second * time.Duration(cmd.SecondsToLive)).Unix()
45: 			expires = &v
46: 		} else if cmd.SecondsToLive < 0 {
47: 			return apikey.ErrInvalidExpiration
48: 		}
49: 
50: 		isRevoked := false
51: 		t := apikey.APIKey{
52: 			OrgID:            cmd.OrgID,
53: 			Name:             cmd.Name,
54: 			Role:             cmd.Role,
55: 			Key:              cmd.Key,
56: 			Created:          updated,
57: 			Updated:          updated,
58: 			Expires:          expires,
59: 			ServiceAccountId: cmd.ServiceAccountID,
60: 			IsRevoked:        &isRevoked,
61: 		}
62: 
63: 		if _, err := sess.Insert(&t); err != nil {
64: 			return fmt.Errorf("%s: %w", "failed to insert token", err)
65: 		}
66: 		res = &t
67: 		return nil
68: 	})
69: 	return res, err
70: }
71: 
72: func (ss *sqlStore) GetApiKeyByName(ctx context.Context, query *apikey.GetByNameQuery) (res *apikey.APIKey, err error) {
73: 	err = ss.db.WithDbSession(ctx, func(sess *db.Session) error {
74: 		var key apikey.APIKey
75: 		has, err := sess.Where("org_id=? AND name=?", query.OrgID, query.KeyName).Get(&key)
76: 
77: 		if err != nil {
78: 			return err
79: 		} else if !has {
80: 			return apikey.ErrInvalid
81: 		}
82: 
83: 		res = &key
84: 		return nil
85: 	})
86: 	return res, err
87: }
88: 
89: func (ss *sqlStore) GetAPIKeyByHash(ctx context.Context, hash string) (*apikey.APIKey, error) {
90: 	var key apikey.APIKey
91: 	err := ss.db.WithDbSession(ctx, func(sess *db.Session) error {
92: 		has, err := sess.Table("api_key").Where(fmt.Sprintf("%s = ?", ss.db.GetDialect().Quote("key")), hash).Get(&key)
93: 		if err != nil {
94: 			return err
95: 		} else if !has {
96: 			return apikey.ErrInvalid
97: 		}
98: 		return nil
99: 	})
100: 	return &key, err
101: }
102: 
103: func (ss *sqlStore) UpdateAPIKeyLastUsedDate(ctx context.Context, tokenID int64) error {
104: 	now := timeNow()
105: 	return ss.db.WithDbSession(ctx, func(sess *db.Session) error {
106: 		if _, err := sess.Table("api_key").ID(tokenID).Cols("last_used_at").Update(&apikey.APIKey{LastUsedAt: &now}); err != nil {
107: 			return err
108: 		}
109: 
110: 		return nil
111: 	})
112: }
113: 
114: func (ss *sqlStore) Count(ctx context.Context, scopeParams *quota.ScopeParameters) (*quota.Map, error) {
115: 	u := &quota.Map{}
116: 	type result struct {
117: 		Count int64
118: 	}
119: 
120: 	r := result{}
121: 	if err := ss.db.WithDbSession(ctx, func(sess *sqlstore.DBSession) error {
122: 		rawSQL := "SELECT COUNT(*) AS count FROM api_key"
123: 		if _, err := sess.SQL(rawSQL).Get(&r); err != nil {
124: 			return err
125: 		}
126: 		return nil
127: 	}); err != nil {
128: 		return u, err
129: 	} else {
130: 		tag, err := quota.NewTag(apikey.QuotaTargetSrv, apikey.QuotaTarget, quota.GlobalScope)
131: 		if err != nil {
132: 			return nil, err
133: 		}
134: 		u.Set(tag, r.Count)
135: 	}
136: 
137: 	if scopeParams != nil && scopeParams.OrgID != 0 {
138: 		if err := ss.db.WithDbSession(ctx, func(sess *sqlstore.DBSession) error {
139: 			rawSQL := "SELECT COUNT(*) AS count FROM api_key WHERE org_id = ?"
140: 			if _, err := sess.SQL(rawSQL, scopeParams.OrgID).Get(&r); err != nil {
141: 				return err
142: 			}
143: 			return nil
144: 		}); err != nil {
145: 			return u, err
146: 		} else {
147: 			tag, err := quota.NewTag(apikey.QuotaTargetSrv, apikey.QuotaTarget, quota.OrgScope)
148: 			if err != nil {
149: 				return nil, err
150: 			}
151: 			u.Set(tag, r.Count)
152: 		}
153: 	}
154: 
155: 	return u, nil
156: }
