{"content":"1: package secretscan
2: 
3: import (
4: 	"context"
5: 	"fmt"
6: 	"time"
7: 
8: 	"github.com/grafana/grafana/pkg/infra/log"
9: 	"github.com/grafana/grafana/pkg/services/apikey"
10: 	"github.com/grafana/grafana/pkg/services/serviceaccounts"
11: 	"github.com/grafana/grafana/pkg/setting"
12: )
13: 
14: const defaultURL = "https://secret-scanning.grafana.net"
15: 
16: type Checker interface {
17: 	CheckTokens(ctx context.Context) error
18: }
19: 
20: type CheckerClient interface {
21: 	CheckTokens(ctx context.Context, keyHashes []string) ([]Token, error)
22: }
23: 
24: type WebHookClient interface {
25: 	Notify(ctx context.Context, token *Token, tokenName string, revoked bool) error
26: }
27: 
28: type SATokenRetriever interface {
29: 	ListTokens(ctx context.Context, query *serviceaccounts.GetSATokensQuery) ([]apikey.APIKey, error)
30: 	RevokeServiceAccountToken(ctx context.Context, orgID, serviceAccountID, tokenID int64) error
31: }
32: 
33: // Secret Scan Service is grafana's service for checking leaked keys.
34: type Service struct {
35: 	store         SATokenRetriever
36: 	client        CheckerClient
37: 	webHookClient WebHookClient
38: 	logger        log.Logger
39: 	webHookNotify bool
40: 	revoke        bool // whether to revoke leaked tokens
41: }
42: 
43: func NewService(store SATokenRetriever, cfg *setting.Cfg) (*Service, error) {
44: 	secretscanBaseURL := cfg.SectionWithEnvOverrides("secretscan").Key("base_url").MustString(defaultURL)
45: 	// URL to send outgoing webhook when a token is leaked.
46: 	oncallURL := cfg.SectionWithEnvOverrides("secretscan").Key("oncall_url").MustString("")
47: 	revoke := cfg.SectionWithEnvOverrides("secretscan").Key("revoke").MustBool(true)
48: 
49: 	client, err := newClient(secretscanBaseURL, cfg.BuildVersion, cfg.Env == setting.Dev)
50: 	if err != nil {
51: 		return nil, fmt.Errorf("failed to create secretscan client: %w", err)
52: 	}
53: 
54: 	var webHookClient WebHookClient
55: 	if oncallURL != "" {
56: 		var errWebhook error
57: 		webHookClient, errWebhook = newWebHookClient(oncallURL, cfg.BuildVersion, cfg.Env == setting.Dev)
58: 		if errWebhook != nil {
59: 			return nil, fmt.Errorf("failed to create secretscan webhook client: %w", errWebhook)
60: 		}
61: 	}
62: 
63: 	return &Service{
64: 		store:         store,
65: 		client:        client,
66: 		webHookClient: webHookClient,
67: 		logger:        log.New("secretscan"),
68: 		webHookNotify: oncallURL != "",
69: 		revoke:        revoke,
70: 	}, nil
71: }
72: 
73: func (s *Service) RetrieveActiveTokens(ctx context.Context) ([]apikey.APIKey, error) {
74: 	saTokens, err := s.store.ListTokens(ctx, &serviceaccounts.GetSATokensQuery{})
75: 	if err != nil {
76: 		return nil, fmt.Errorf("failed to retrieve service account tokens: %w", err)
77: 	}
78: 
79: 	return saTokens, nil
80: }
81: 
82: // hasExpired returns true if the token has expired.
83: // Duplicate to SA API. Remerge.
84: func hasExpired(expiration *int64) bool {
85: 	if expiration == nil {
86: 		return false
87: 	}
88: 
89: 	v := time.Unix(*expiration, 0)
90: 
91: 	return (v).Before(time.Now())
92: }
93: 
94: // CheckTokens checks for leaked tokens.
95: func (s *Service) CheckTokens(ctx context.Context) error {
96: 	// Retrieve all active tokens from the database.
97: 	tokens, err := s.RetrieveActiveTokens(ctx)
98: 	if err != nil {
99: 		return fmt.Errorf("failed to retrieve tokens for checking: %w", err)
100: 	}
101: 
102: 	hashes, hashMap := s.filterCheckableTokens(tokens)
103: 	if len(hashes) == 0 {
104: 		s.logger.Debug("No active tokens to check")
105: 
106: 		return nil
107: 	}
108: 
109: 	// Check if any leaked tokens exist.
110: 	secretscanTokens, err := s.client.CheckTokens(ctx, hashes)
111: 	if err != nil {
112: 		return fmt.Errorf("failed to check tokens: %w", err)
113: 	}
114: 
115: 	// Revoke leaked tokens.
116: 	// Could be done in bulk but we don't expect more than 1 or 2 tokens to be leaked per check.
117: 	for _, secretscanToken := range secretscanTokens {
118: 		secretscanToken := secretscanToken
119: 		leakedToken := hashMap[secretscanToken.Hash]
120: 
121: 		if s.revoke {
122: 			if err := s.store.RevokeServiceAccountToken(
123: 				ctx, leakedToken.OrgID, *leakedToken.ServiceAccountId, leakedToken.ID); err != nil {
124: 				s.logger.Error("Failed to delete leaked token. Revoke manually.",
125: 					"error", err, "url", secretscanToken.URL, "reported_at", secretscanToken.ReportedAt,
126: 					"token_id", leakedToken.ID, "token", leakedToken.Name, "org", leakedToken.OrgID,
127: 					"serviceAccount", *leakedToken.ServiceAccountId)
128: 			}
129: 		}
130: 
131: 		if s.webHookNotify {
132: 			if err := s.webHookClient.Notify(ctx, &secretscanToken, leakedToken.Name, s.revoke); err != nil {
133: 				s.logger.Warn("Failed to call token leak webhook", "error", err)
134: 			}
135: 		}
136: 
137: 		s.logger.Warn("Found leaked token",
138: 			"url", secretscanToken.URL, "reported_at", secretscanToken.ReportedAt,
139: 			"token_id", leakedToken.ID, "token", leakedToken.Name, "org", leakedToken.OrgID,
140: 			"serviceAccount", *leakedToken.ServiceAccountId, "revoked", s.revoke)
141: 	}
142: 
143: 	return nil
144: }
145: 
146: // filterCheckableTokens returns a list of tokens that can be checked and a map of tokens to their hashes.
147: func (*Service) filterCheckableTokens(tokens []apikey.APIKey) ([]string, map[string]apikey.APIKey) {
148: 	hashes := make([]string, 0, len(tokens))
149: 	hashMap := make(map[string]apikey.APIKey)
150: 
151: 	for _, token := range tokens {
152: 		if hasExpired(token.Expires) || (token.IsRevoked != nil && *token.IsRevoked) {
153: 			continue
154: 		}
155: 
156: 		hashes = append(hashes, token.Key)
157: 		hashMap[token.Key] = token
158: 	}
159: 
160: 	return hashes, hashMap
161: }
