24: )
25: 
26: type AuthOptions struct {
27: 	ReqGrafanaAdmin bool
28: 	ReqNoAnonynmous bool
29: 	ReqSignedIn     bool
30: }
31: 
32: func accessForbidden(c *contextmodel.ReqContext) {
33: 	if c.IsApiRequest() {
34: 		c.JsonApiErr(403, "Permission denied", nil)
35: 		return
36: 	}
37: 
38: 	c.Redirect(setting.AppSubUrl + "/")
39: }
40: 
41: func notAuthorized(c *contextmodel.ReqContext) {
42: 	if c.IsApiRequest() {
43: 		c.WriteErrOrFallback(http.StatusUnauthorized, http.StatusText(http.StatusUnauthorized), c.LookupTokenErr)
44: 		return
45: 	}
46: 
47: 	if !c.UseSessionStorageRedirect {
48: 		writeRedirectCookie(c)
49: 	}
50: 
51: 	if errors.Is(c.LookupTokenErr, authn.ErrTokenNeedsRotation) {
52: 		if !c.UseSessionStorageRedirect {
53: 			c.Redirect(setting.AppSubUrl + "/user/auth-tokens/rotate")
54: 			return
55: 		}
56: 
57: 		c.Redirect(setting.AppSubUrl + "/user/auth-tokens/rotate" + getRedirectToQueryParam(c))
58: 		return
59: 	}
60: 
61: 	if !c.UseSessionStorageRedirect {
62: 		c.Redirect(setting.AppSubUrl + "/login")
63: 		return
64: 	}
65: 
66: 	c.Redirect(setting.AppSubUrl + "/login" + getRedirectToQueryParam(c))
67: }
68: 
69: func tokenRevoked(c *contextmodel.ReqContext, err *auth.TokenRevokedError) {
70: 	if c.IsApiRequest() {
71: 		c.JSON(http.StatusUnauthorized, map[string]any{
72: 			"message": "Token revoked",
73: 			"error": map[string]any{
74: 				"id":                    "ERR_TOKEN_REVOKED",
75: 				"maxConcurrentSessions": err.MaxConcurrentSessions,
76: 			},
77: 		})
78: 		return
79: 	}
80: 
81: 	if !c.UseSessionStorageRedirect {
82: 		writeRedirectCookie(c)
83: 		c.Redirect(setting.AppSubUrl + "/login")
84: 		return
85: 	}
86: 
87: 	c.Redirect(setting.AppSubUrl + "/login" + getRedirectToQueryParam(c))
88: }
89: 
90: func writeRedirectCookie(c *contextmodel.ReqContext) {
91: 	redirectTo := c.Req.RequestURI
92: 	if setting.AppSubUrl != "" && !strings.HasPrefix(redirectTo, setting.AppSubUrl) {
93: 		redirectTo = setting.AppSubUrl + c.Req.RequestURI
94: 	}
95: 
96: 	if redirectTo == "/" {
97: 		return
98: 	}
99: 
100: 	// remove any forceLogin=true params
101: 	redirectTo = RemoveForceLoginParams(redirectTo)
102: 	cookies.WriteCookie(c.Resp, "redirect_to", url.QueryEscape(redirectTo), 0, nil)
103: }
104: 
105: func getRedirectToQueryParam(c *contextmodel.ReqContext) string {
106: 	redirectTo := c.Req.RequestURI
107: 	if setting.AppSubUrl != "" && strings.HasPrefix(redirectTo, setting.AppSubUrl) {
108: 		redirectTo = strings.TrimPrefix(redirectTo, setting.AppSubUrl)
109: 	}
110: 
111: 	if redirectTo == "/" {
112: 		return ""
113: 	}
114: 
115: 	// remove any forceLogin=true params
116: 	redirectTo = RemoveForceLoginParams(redirectTo)
117: 	return "?redirectTo=" + url.QueryEscape(redirectTo)
118: }
119: 
120: var forceLoginParamsRegexp = regexp.MustCompile(`&?forceLogin=true`)
121: 
122: func RemoveForceLoginParams(str string) string {
123: 	return forceLoginParamsRegexp.ReplaceAllString(str, "")
124: }
125: 
126: func CanAdminPlugins(cfg *setting.Cfg, accessControl ac.AccessControl) func(c *contextmodel.ReqContext) {
127: 	return func(c *contextmodel.ReqContext) {
128: 		hasAccess := ac.HasAccess(accessControl, c)
129: 		if !pluginaccesscontrol.ReqCanAdminPlugins(cfg)(c) && !hasAccess(pluginaccesscontrol.AdminAccessEvaluator) {
130: 			accessForbidden(c)
131: 			return
132: 		}
133: 		if c.AllowAnonymous && !c.IsSignedIn && shouldForceLogin(c) {
134: 			notAuthorized(c)
135: 			return
136: 		}
137: 	}
138: }
139: 
140: func RoleAppPluginAuth(accessControl ac.AccessControl, ps pluginstore.Store, logger log.Logger) func(c *contextmodel.ReqContext) {
141: 	return func(c *contextmodel.ReqContext) {
142: 		pluginID := web.Params(c.Req)[":id"]
143: 		p, exists := ps.Plugin(c.Req.Context(), pluginID)
144: 		if !exists {
145: 			// The frontend will handle app not found appropriately
146: 			return
147: 		}
148: 
149: 		permitted := true
150: 		path := normalizeIncludePath(c.Req.URL.Path)
151: 		hasAccess := ac.HasAccess(accessControl, c)
152: 		for _, i := range p.Includes {
153: 			if i.Type != "page" {
154: 				continue
155: 			}
156: 
157: 			u, err := url.Parse(i.Path)
158: 			if err != nil {
159: 				logger.Error("failed to parse include path", "pluginId", pluginID, "include", i.Name, "err", err)
160: 				continue
161: 			}
162: 
163: 			if normalizeIncludePath(u.Path) == path {
164: 				if i.RequiresRBACAction() && !hasAccess(pluginaccesscontrol.GetPluginRouteEvaluator(pluginID, i.Action)) {
165: 					logger.Debug("Plugin include is covered by RBAC, user doesn't have access", "plugin", pluginID, "include", i.Name)
166: 					permitted = false
167: 					break
168: 				} else if !i.RequiresRBACAction() && !c.HasUserRole(i.Role) {
169: 					permitted = false
170: 					break
171: 				}
172: 			}
173: 		}
174: 
175: 		if !permitted {
176: 			accessForbidden(c)
177: 			return
178: 		}
179: 	}
180: }
