45: func (s *RBACSync) SyncPermissionsHook(ctx context.Context, ident *authn.Identity, _ *authn.Request) error {
46: 	ctx, span := s.tracer.Start(ctx, "rbac.sync.SyncPermissionsHook")
47: 	defer span.End()
48: 
49: 	if !ident.ClientParams.SyncPermissions {
50: 		return nil
51: 	}
52: 
53: 	// Populate permissions from roles
54: 	permissions, err := s.fetchPermissions(ctx, ident)
55: 	if err != nil {
56: 		return err
57: 	}
58: 
59: 	if ident.Permissions == nil {
60: 		ident.Permissions = make(map[int64]map[string][]string, 1)
61: 	}
62: 
63: 	grouped := accesscontrol.GroupScopesByActionContext(ctx, permissions)
64: 
65: 	// Restrict access to the list of actions
66: 	actionsLookup := ident.ClientParams.FetchPermissionsParams.RestrictedActions
67: 	if len(actionsLookup) > 0 {
68: 		filtered := make(map[string][]string, len(actionsLookup))
69: 		for _, action := range actionsLookup {
70: 			if scopes, ok := grouped[action]; ok {
71: 				filtered[action] = scopes
72: 			}
73: 		}
74: 		grouped = filtered
75: 	}
76: 	ident.Permissions[ident.OrgID] = grouped
77: 
78: 	return nil
79: }
80: 
81: func (s *RBACSync) fetchPermissions(ctx context.Context, ident *authn.Identity) ([]accesscontrol.Permission, error) {
82: 	ctx, span := s.tracer.Start(ctx, "rbac.sync.fetchPermissions")
83: 	defer span.End()
84: 
85: 	permissions := make([]accesscontrol.Permission, 0, 8)
86: 	roles := ident.ClientParams.FetchPermissionsParams.Roles
87: 	actions := ident.ClientParams.FetchPermissionsParams.AllowedActions
88: 	k8s := ident.ClientParams.FetchPermissionsParams.K8s
89: 	if len(roles) > 0 || len(actions) > 0 || len(k8s) > 0 {
90: 		for _, role := range roles {
91: 			roleDTO, err := s.ac.GetRoleByName(ctx, ident.GetOrgID(), role)
92: 			if err != nil && !errors.Is(err, accesscontrol.ErrRoleNotFound) {
93: 				s.log.FromContext(ctx).Error("Failed to fetch role from db", "error", err, "role", role)
94: 				return nil, errSyncPermissionsForbidden
95: 			}
96: 			if roleDTO != nil {
97: 				permissions = append(permissions, roleDTO.Permissions...)
98: 			}
99: 		}
100: 		for _, action := range actions {
101: 			s.addPermissionsForAction(action, &permissions)
102: 		}
103: 		// Add K8s permissions
104: 		k8sPermissions := s.translateK8sPermissions(ctx, k8s)
105: 		permissions = append(permissions, k8sPermissions...)
106: 		return permissions, nil
107: 	}
108: 
109: 	permissions, err := s.ac.GetUserPermissions(ctx, ident, accesscontrol.Options{ReloadCache: false})
110: 	if err != nil {
111: 		s.log.FromContext(ctx).Error("Failed to fetch permissions from db", "error", err, "id", ident.ID)
112: 		return nil, errSyncPermissionsForbidden
113: 	}
114: 	return permissions, nil
115: }
