117: // addPermissionsForAction is a helper method that handles the common pattern of:
118: // 1. Getting scope prefixes for an action
119: // 2. Adding permissions with appropriate scopes
120: // 3. Logging warnings for unknown actions
121: func (s *RBACSync) addPermissionsForAction(action string, permissions *[]accesscontrol.Permission) {
122: 	scopes, ok := s.permRegistry.GetScopePrefixes(action)
123: 	if !ok {
124: 		s.log.Warn("Unknown action scopes", "action", action)
125: 		return
126: 	}
127: 	if len(scopes) == 0 {
128: 		*permissions = append(*permissions, accesscontrol.Permission{Action: action})
129: 		return
130: 	}
131: 	for scope := range scopes {
132: 		*permissions = append(*permissions, accesscontrol.Permission{Action: action, Scope: scope + "*"})
133: 	}
134: }
