136: func (s *RBACSync) translateK8sPermissions(_ context.Context, k8sPerms []string) []accesscontrol.Permission {
137: 	permissions := make([]accesscontrol.Permission, 0, len(k8sPerms))
138: 	for _, k8sPerm := range k8sPerms {
139: 		parts := strings.Split(k8sPerm, ":")
140: 		if len(parts) != 2 {
141: 			s.log.Warn("Invalid K8s permission format", "permission", k8sPerm)
142: 			continue
143: 		}
144: 		groupResource := strings.Split(parts[0], "/")
145: 		group := groupResource[0]
146: 		verb := parts[1]
147: 		switch {
148: 		case len(groupResource) == 1:
149: 			// Case group:verb
150: 			resourceMappings := s.mapper.GetAll(group)
151: 			if len(resourceMappings) == 0 {
152: 				s.log.Warn("No mappings found for group", "group", group)
153: 				continue
154: 			}
155: 			for _, mapping := range resourceMappings {
156: 				if verb == "*" {
157: 					actions := mapping.AllActions()
158: 					for _, action := range actions {
159: 						s.addPermissionsForAction(action, &permissions)
160: 					}
161: 					continue
162: 				}
163: 				action, ok := mapping.Action(verb)
164: 				if !ok {
165: 					s.log.Warn("Unknown K8s verb for group", "group", group, "verb", verb)
166: 					continue
167: 				}
168: 				s.addPermissionsForAction(action, &permissions)
169: 			}
170: 		case len(groupResource) == 2:
171: 			// Case group/resource:verb
172: 			resource := groupResource[1]
173: 			resourceMappings, ok := s.mapper.Get(group, resource)
174: 			if !ok {
175: 				s.log.Warn("Unknown K8s resource", "group", group, "resource", resource)
176: 				continue
177: 			}
178: 			if verb == "*" {
179: 				actions := resourceMappings.AllActions()
180: 				for _, action := range actions {
181: 					s.addPermissionsForAction(action, &permissions)
182: 				}
183: 				continue
184: 			}
185: 			action, ok := resourceMappings.Action(verb)
186: 			if !ok {
187: 				s.log.Warn("Unknown K8s verb", "group", group, "resource", resource, "verb", verb)
188: 				continue
189: 			}
190: 			s.addPermissionsForAction(action, &permissions)
191: 		default:
192: 			s.log.Warn("Invalid K8s permission format", "permission", k8sPerm)
193: 			continue
194: 		}
195: 	}
196: 	return permissions
197: }
