199: func cloudRolesToAddAndRemove(ident *authn.Identity) ([]string, []string, error) {
200: 	// Since Cloud Admin/Editor/Viewer roles are not yet implemented one-to-one in the Grafana, it becomes a confusing experience for users,
201: 	// therefore we are doing granular mapping of all available functionality in the Grafana temporary.
202: 	var fixedCloudRoles = map[org.RoleType][]string{
203: 		org.RoleViewer: {accesscontrol.FixedCloudViewerRole, accesscontrol.FixedCloudSupportTicketReader},
204: 		org.RoleEditor: {accesscontrol.FixedCloudEditorRole, accesscontrol.FixedCloudSupportTicketAdmin},
205: 		org.RoleAdmin:  {accesscontrol.FixedCloudAdminRole, accesscontrol.FixedCloudSupportTicketAdmin},
206: 	}
207: 
208: 	rolesToAdd := make(map[string]bool)
209: 	rolesToRemove := make([]string, 0, 4)
210: 
211: 	currentRole := ident.GetOrgRole()
212: 	_, validRole := fixedCloudRoles[currentRole]
213: 
214: 	if !validRole {
215: 		return nil, nil, errInvalidCloudRole.Errorf("invalid role: %s", currentRole)
216: 	}
217: 
218: 	// Add roles for the current role and track them
219: 	for _, fixedRole := range fixedCloudRoles[currentRole] {
220: 		rolesToAdd[fixedRole] = true
221: 	}
222: 
223: 	// Add roles to remove, ensuring we don't remove any that have been added
224: 	for role, fixedRoles := range fixedCloudRoles {
225: 		if role == currentRole {
226: 			continue
227: 		}
228: 		for _, fixedRole := range fixedRoles {
229: 			if _, ok := rolesToAdd[fixedRole]; !ok {
230: 				rolesToRemove = append(rolesToRemove, fixedRole)
231: 			}
232: 		}
233: 	}
234: 
235: 	return maps.Keys(rolesToAdd), rolesToRemove, nil
236: }
237: 
238: func (s *RBACSync) SyncCloudRoles(ctx context.Context, ident *authn.Identity, r *authn.Request) error {
239: 	ctx, span := s.tracer.Start(ctx, "rbac.sync.SyncCloudRoles")
240: 	defer span.End()
241: 
242: 	// we only want to run this hook during login and if the module used is grafana com
243: 	if r.GetMeta(authn.MetaKeyAuthModule) != login.GrafanaComAuthModule {
244: 		return nil
245: 	}
246: 
247: 	if !ident.IsIdentityType(claims.TypeUser) {
248: 		s.log.FromContext(ctx).Debug("Skip syncing cloud role", "id", ident.ID)
249: 		return nil
250: 	}
251: 
252: 	userID, err := ident.GetInternalID()
253: 	if err != nil {
254: 		return err
255: 	}
256: 
257: 	rolesToAdd, rolesToRemove, err := cloudRolesToAddAndRemove(ident)
258: 	if err != nil {
259: 		return err
260: 	}
261: 
262: 	return s.ac.SyncUserRoles(ctx, ident.GetOrgID(), accesscontrol.SyncUserRolesCommand{
263: 		UserID:        userID,
264: 		RolesToAdd:    rolesToAdd,
265: 		RolesToRemove: rolesToRemove,
266: 	})
267: }
