269: // ClearUserPermissionCacheHook clears a user's permission cache if user Login succeeded. Necessary so that if a user logs in
270: // through different SSO providers with different roles assigned in each, they do not get the wrong permissions.
271: func (s *RBACSync) ClearUserPermissionCacheHook(ctx context.Context, ident *authn.Identity, r *authn.Request, err error) {
272: 	ctx, span := s.tracer.Start(ctx, "rbac.sync.ClearUserPermissionCacheHook")
273: 	defer span.End()
274: 
275: 	if err != nil {
276: 		return
277: 	}
278: 
279: 	ctxLogger := s.log.FromContext(ctx)
280: 	if !ident.IsIdentityType(claims.TypeUser) {
281: 		ctxLogger.Debug("Skipping user permission cache clear, not a user", "type", ident.GetIdentityType())
282: 		return
283: 	}
284: 
285: 	s.ac.ClearUserPermissionCache(ident)
286: }
